mapper.select:
SELECT f.fund_id, f.fund_code, f.fund_name, f.fund_type, f.risk_level, f.company_id, COALESCE(c.company_name, 'N/A') AS company_name, COALESCE(cm.manager_name, 'N/A') AS manager_name, f.fund_scale, f.establish_date, pm.return_rate AS return_1y, COALESCE(pm.max_drawdown, CASE WHEN f.risk_level = 'HIGH' THEN 35.00 WHEN f.risk_level = 'MEDIUM_HIGH' THEN 25.00 WHEN f.risk_level = 'MEDIUM' THEN 18.00 WHEN f.risk_level = 'MEDIUM_LOW' THEN 10.00 WHEN f.risk_level = 'LOW' THEN 3.00 ELSE 15.00 END ) AS max_drawdown, pm.volatility AS volatility, pm.sharpe_ratio AS sharpe_ratio, s.total_score, s.recommend_level, ft.tag_text FROM fund_info f LEFT JOIN fund_company c ON c.company_id = f.company_id LEFT JOIN s ON s.fund_id = f.fund_id LEFT JOIN pm ON pm.fund_id = f.fund_id LEFT JOIN cm ON cm.fund_id = f.fund_id LEFT JOIN ft ON ft.fund_id = f.fund_id
AND f.status = 1
AND f.fund_code LIKE CONCAT('%', #{query.fundCode}, '%')
AND (f.fund_name LIKE CONCAT('%', #{query.keyword}, '%') OR c.company_name LIKE CONCAT('%', #{query.keyword}, '%') OR cm.manager_name LIKE CONCAT('%', #{query.keyword}, '%'))
AND (c.company_name LIKE CONCAT('%', #{query.companyName}, '%') OR f.fund_name LIKE CONCAT('%', #{query.companyName}, '%'))
AND EXISTS ( SELECT 1 FROM fund_manager_relation fmr2 INNER JOIN fund_manager fm2 ON fm2.manager_id = fmr2.manager_id WHERE fmr2.fund_id = f.fund_id AND fm2.manager_name LIKE CONCAT('%', #{query.managerName}, '%') )
AND ( f.fund_type = #{query.fundType} OR f.fund_type LIKE CONCAT(#{query.fundType}, '%') OR f.fund_type LIKE CONCAT('%', #{query.fundType}, '%') )
AND f.risk_level = 'LOW'
AND f.risk_level = 'MEDIUM_LOW'
AND f.risk_level = 'MEDIUM'
AND (f.risk_level = 'MEDIUM_HIGH' OR f.risk_level = 'HIGH')
AND f.risk_level = 'HIGH'
AND f.risk_level = #{query.riskLevel}
AND f.company_id = #{query.companyId}
AND s.total_score >= #{query.minScore}
AND s.total_score <= #{query.maxScore}
AND EXISTS ( SELECT 1 FROM fund_tag_relation ftr WHERE ftr.fund_id = f.fund_id AND ftr.tag_id IN
#{tagId}
)
AND EXISTS ( SELECT 1 FROM fund_tag_relation ftr2 INNER JOIN fund_tag ft2 ON ft2.tag_id = ftr2.tag_id WHERE ftr2.fund_id = f.fund_id AND (ft2.tag_name LIKE CONCAT('%', #{query.tag}, '%') OR ft2.tag_code = #{query.tag}) )
AND f.fund_scale >= #{query.scaleMin}
AND pm.return_rate >= #{query.minReturn}
AND pm.return_rate <= #{query.maxReturn}
AND COALESCE(pm.max_drawdown, CASE WHEN f.risk_level = 'HIGH' THEN 35.00 WHEN f.risk_level = 'MEDIUM_HIGH' THEN 25.00 WHEN f.risk_level = 'MEDIUM' THEN 18.00 WHEN f.risk_level = 'MEDIUM_LOW' THEN 10.00 WHEN f.risk_level = 'LOW' THEN 3.00 ELSE 15.00 END ) <= #{query.maxDrawdown}
ORDER BY s.total_score DESC NULLS LAST, f.fund_id DESC
